static int my_driver_suspend(struct device *dev)
{
    struct my_data *data = dev_get_drvdata(dev);
    /* 하드웨어 상태 저장 */
    data->saved_reg = readl(data->base + REG_CTRL);
    /* 클럭 비활성화 */
    clk_disable_unprepare(data->clk);
    return 0;
}

static int my_driver_resume(struct device *dev)
{
    struct my_data *data = dev_get_drvdata(dev);
    clk_prepare_enable(data->clk);
    writel(data->saved_reg, data->base + REG_CTRL);
    return 0;
}

